// ── Azure Blob Storage ─────────────────────────────────────────────────────────
const BLOB_URL = "https://subzerocrmdata.blob.core.windows.net/crm-data/builders.json?sv=2026-02-06&ss=b&srt=co&sp=rwdlactfx&se=2031-01-01T01:23:08Z&st=2026-06-29T17:08:08Z&spr=https&sig=V%2FlnJScaJs2nhy3Nrc3Mrsz97Bo%2F8O3mEWAYsFfIV%2Bk%3D";
const CONTAINER_URL = "https://subzerocrmdata.blob.core.windows.net/crm-data?restype=container&sv=2026-02-06&ss=b&srt=co&sp=rwdlactfx&se=2031-01-01T01:23:08Z&st=2026-06-29T17:08:08Z&spr=https&sig=V%2FlnJScaJs2nhy3Nrc3Mrsz97Bo%2F8O3mEWAYsFfIV%2Bk%3D";
async function loadFromBlob() {
    try {
        const res = await fetch(BLOB_URL, {
            cache: "no-store"
        });
        if (res.status === 404) return {
            data: null,
            error: null,
            raw: ""
        }; // blob genuinely doesn't exist yet — safe, new setup
        if (!res.ok) return {
            data: null,
            error: `HTTP ${res.status}`,
            raw: null
        };
        const raw = await res.text();
        let data = null;
        try {
            data = raw ? JSON.parse(raw) : null;
        } catch  {
            return {
                data: null,
                error: "corrupt data on server",
                raw: null
            };
        }
        return {
            data,
            error: null,
            raw
        };
    } catch (err) {
        return {
            data: null,
            error: (err && err.message) || "network error",
            raw: null
        };
    }
}
// Fetch the raw current blob text, used right before saving to check nobody else has written since we last synced.
// Returns null to mean "couldn't verify" (caller should treat this as unsafe to save).
async function fetchRawBlob() {
    try {
        const res = await fetch(BLOB_URL, {
            cache: "no-store"
        });
        if (res.status === 404) return "";
        if (!res.ok) return null;
        return await res.text();
    } catch  {
        return null;
    }
}
async function saveToBlob(data) {
    try {
        // First ensure container exists
        await fetch(CONTAINER_URL, {
            method: "PUT"
        });
        // Save data
        const res = await fetch(BLOB_URL, {
            method: "PUT",
            headers: {
                "x-ms-blob-type": "BlockBlob",
                "Content-Type": "application/json"
            },
            body: JSON.stringify(data)
        });
        return res.ok;
    } catch  {
        return false;
    }
}
function useAzureStorage(builders, setBuilders, setLoading) {
    const [syncing, setSyncing] = useState(false);
    const [lastSaved, setLastSaved] = useState(null);
    const [loadError, setLoadError] = useState(null);
    const [conflict, setConflict] = useState(false);
    const loadedRef = useRef(false);
    // Raw JSON text of the last version of the data we know is on the server
    // (from our own load, or our own last successful save). Used to detect
    // whether another tab/session has written to the blob since then.
    const lastSyncedRawRef = useRef(null);
    const saveTimer = useRef(null);
    // Load from blob on mount
    useEffect(()=>{
        setLoading(true);
        loadFromBlob().then(({ data, error, raw })=>{
            if (error) {
                // Load failed — do NOT allow autosave to run, or it could overwrite
                // real cloud data with local seed/default data. Surface the error instead.
                setLoadError(error);
                loadedRef.current = false;
            } else {
                if (data && Array.isArray(data) && data.length > 0) {
                    setBuilders(data);
                }
                lastSyncedRawRef.current = raw;
                loadedRef.current = true;
            }
            setLoading(false);
        });
    }, []);
    // Auto-save to blob whenever builders change (debounced 3s).
    // Gated on loadedRef so a failed initial load can never trigger an overwrite.
    // Before writing, re-checks the server copy against what we last knew — if it
    // changed (another tab/session saved since), we refuse to blindly overwrite it
    // and instead flag a conflict for the user to resolve by reloading.
    useEffect(()=>{
        if (!loadedRef.current || conflict) return;
        if (saveTimer.current) clearTimeout(saveTimer.current);
        saveTimer.current = setTimeout(async ()=>{
            setSyncing(true);
            const currentRemoteRaw = await fetchRawBlob();
            if (currentRemoteRaw === null) {
                // Couldn't verify current server state — safer to skip this save than risk clobbering.
                setSyncing(false);
                return;
            }
            if (lastSyncedRawRef.current !== null && currentRemoteRaw !== lastSyncedRawRef.current) {
                // Someone else changed the data since we last synced. Do not overwrite.
                setConflict(true);
                setSyncing(false);
                return;
            }
            const newRaw = JSON.stringify(builders);
            const ok = await saveToBlob(builders);
            if (ok) {
                lastSyncedRawRef.current = newRaw;
                setLastSaved(new Date());
            }
            setSyncing(false);
        }, 3000);
        return ()=>clearTimeout(saveTimer.current);
    }, [
        builders
    ]);
    return {
        syncing,
        lastSaved,
        loadError,
        conflict
    };
}
// ── Duplicate address detection ───────────────────────────────────────────────
function buildDupeSet(builders) {
    const addrCount = {};
    builders.forEach((b)=>b.jobs.forEach((j)=>{
            if (!j.address) return;
            const key = j.address.trim().toLowerCase();
            addrCount[key] = (addrCount[key] || 0) + 1;
        }));
    return new Set(Object.entries(addrCount).filter(([, c])=>c > 1).map(([a])=>a));
}
// ── Geocoder ──────────────────────────────────────────────────────────────────
// Nominatim geocoding cache — key = address string, value = {lat, lng}
const GEO_CACHE_KEY = "crm_geocache_v1";
async function geocodeAddress(address) {
    if (!address || address.trim().length < 5) return null;
    try {
        const url = `https://nominatim.openstreetmap.org/search?format=json&limit=1&q=${encodeURIComponent(address)}`;
        const res = await fetch(url, {
            headers: {
                "User-Agent": "SubZeroBuilderCRM/1.0"
            }
        });
        const data = await res.json();
        if (data?.[0]) return {
            lat: parseFloat(data[0].lat),
            lng: parseFloat(data[0].lon)
        };
    } catch  {}
    return null;
}
function useGeocoder(builders, setBuilders) {
    const [queue, setQueue] = useState([]);
    const [progress, setProgress] = useState({
        total: 0,
        done: 0,
        running: false
    });
    const runningRef = useRef(false);
    const cacheRef = useRef({});
    // Load cache from storage on mount
    useEffect(()=>{
        try {
            window.storage?.get(GEO_CACHE_KEY).then((r)=>{
                if (r?.value) cacheRef.current = JSON.parse(r.value);
            });
        } catch  {}
    }, []);
    // Build queue whenever builders change — find anything missing lat/lng
    useEffect(()=>{
        const needed = [];
        builders.forEach((b)=>{
            if (!b.lat && b.address) needed.push({
                type: "builder",
                id: b.id,
                address: b.address
            });
            b.jobs.forEach((j)=>{
                if (!j.lat && j.address) needed.push({
                    type: "job",
                    builderId: b.id,
                    id: j.id,
                    address: j.address
                });
            });
        });
        // Filter out ones already in cache
        const toFetch = needed.filter((n)=>!cacheRef.current[n.address]);
        if (toFetch.length > 0) {
            setQueue(toFetch);
            setProgress((p)=>({
                    ...p,
                    total: toFetch.length,
                    done: 0
                }));
        }
    }, []); // Only on mount — new items added via addToQueue
    const addToQueue = (newItems)=>{
        const toFetch = newItems.filter((n)=>!cacheRef.current[n.address]);
        if (toFetch.length === 0) return;
        setQueue((q)=>[
                ...q,
                ...toFetch
            ]);
        setProgress((p)=>({
                ...p,
                total: p.total + toFetch.length
            }));
    };
    // Process queue 1 per second
    useEffect(()=>{
        if (queue.length === 0 || runningRef.current) return;
        runningRef.current = true;
        setProgress((p)=>({
                ...p,
                running: true
            }));
        let idx = 0;
        const processNext = async ()=>{
            if (idx >= queue.length) {
                runningRef.current = false;
                setProgress((p)=>({
                        ...p,
                        running: false
                    }));
                setQueue([]);
                return;
            }
            const item = queue[idx++];
            // Check cache first
            if (cacheRef.current[item.address]) {
                const { lat, lng } = cacheRef.current[item.address];
                applyCoords(item, lat, lng);
                setProgress((p)=>({
                        ...p,
                        done: p.done + 1
                    }));
                setTimeout(processNext, 50);
                return;
            }
            const coords = await geocodeAddress(item.address);
            if (coords) {
                cacheRef.current[item.address] = coords;
                try {
                    window.storage?.set(GEO_CACHE_KEY, JSON.stringify(cacheRef.current));
                } catch  {}
                applyCoords(item, coords.lat, coords.lng);
            }
            setProgress((p)=>({
                    ...p,
                    done: p.done + 1
                }));
            setTimeout(processNext, 1100); // 1.1s to stay under Nominatim rate limit
        };
        processNext();
    }, [
        queue
    ]);
    const applyCoords = (item, lat, lng)=>{
        setBuilders((prev)=>prev.map((b)=>{
                if (item.type === "builder" && b.id === item.id) return {
                    ...b,
                    lat,
                    lng
                };
                if (item.type === "job" && b.id === item.builderId) {
                    return {
                        ...b,
                        jobs: b.jobs.map((j)=>j.id === item.id ? {
                                ...j,
                                lat,
                                lng
                            } : j)
                    };
                }
                return b;
            }));
    };
    return {
        progress,
        addToQueue
    };
}
